import { z } from "zod";

export const sentimentRequestSchema = z.object({
  text: z.string().min(1).max(50000),
  granularity: z.enum(["document", "sentence"]).optional().default("document"),
});

export const sentimentSentenceSchema = z.object({
  text: z.string(),
  sentiment: z.enum(["positive", "negative", "neutral", "mixed"]),
  score: z.number().min(-1).max(1),
});

export const sentimentResponseSchema = z.object({
  sentiment: z.enum(["positive", "negative", "neutral", "mixed"]),
  score: z.number().min(-1).max(1),
  confidence: z.number().min(0).max(1),
  sentences: z.array(sentimentSentenceSchema).optional(),
});

export type SentimentRequest = z.infer<typeof sentimentRequestSchema>;
export type SentimentResponse = z.infer<typeof sentimentResponseSchema>;
export type SentimentSentence = z.infer<typeof sentimentSentenceSchema>;
